import{_ as i}from"./plugin-vue_export-helper-c27b6911.js";import{o as l,c as a,e}from"./app-3258b326.js";const r={},h=e('<h1 id="魅魔雾气中魅惑晶核提取及解魅剂的制备" tabindex="-1"><a class="header-anchor" href="#魅魔雾气中魅惑晶核提取及解魅剂的制备" aria-hidden="true">#</a> 魅魔雾气中魅惑晶核提取及解魅剂的制备</h1><h2 id="实验目的" tabindex="-1"><a class="header-anchor" href="#实验目的" aria-hidden="true">#</a> 实验目的</h2><ol><li>了解魅魔雾气的主要成分，掌握提纯魅惑晶核的方法；</li><li>掌握利用具人化魅魔唾液和桃心尾端制备解魅剂的方法；</li><li>练习气气分离和雾气凝华等基本实验技能。</li></ol><h2 id="实验原理" tabindex="-1"><a class="header-anchor" href="#实验原理" aria-hidden="true">#</a> 实验原理</h2><p>魅魔是地狱魔鬼的一种，特殊无定形外貌，看起来像一团飘动的五颜六色雾气。在猎物引起它们注意的情况下，魅魔会凝聚形成与猎物心上人相似的样子。魅魔雾气中含有麻醉因子和魅惑晶核，前者会导致猎物全身肌肉松弛，后者引起猎物燥热难耐且精神恍惚。倘若未及时用法术清理呼吸道，几分钟后猎物会感到性兴奋，并在梦幻中感到心上人在与自己交媾。</p><p>通过气气分离和雾气凝华技术，我们可以分离并提取魅魔雾气中的魅惑晶核，用作必要时刻的催情剂。有趣的是，魅魔具人化后，其唾液中的消化因子可以与桃心尾端的黑色蛋白发生魔化反应，生成可溶性小分子。简单过滤掉未被魔化的残余尾端，剩下的液体可作为解魅剂，用以解救被魅魔魅惑的个体。</p><h2 id="实验仪器及试剂" tabindex="-1"><a class="header-anchor" href="#实验仪器及试剂" aria-hidden="true">#</a> 实验仪器及试剂</h2><ul><li><p>仪器</p><ul><li>气气分离仪</li><li>精华压锅</li><li>高脚金属漏斗</li><li>魔法坩埚（适配魔法火焰）</li><li>塑料口套</li></ul></li><li><p>试剂</p><ul><li>魅魔雾气（用以诱导具人魅魔的产生，剪取桃心尾端和采集唾液）</li></ul></li></ul><h2 id="操作方法与实验步骤" tabindex="-1"><a class="header-anchor" href="#操作方法与实验步骤" aria-hidden="true">#</a> 操作方法与实验步骤</h2><ol><li>一名小组成员作为诱导员，让魅魔雾气具人化，另一人采集桃心尾端。</li><li>诱导员佩戴塑料口套，靠近魅魔口唇部进行唾液采集。</li><li>使用分离仪分离魅惑晶核气化物，用凝华压锅完成晶核提取。</li><li>将桃心尾端和魅魔唾液倒入魔法坩埚，使用魔法火焰加热10分钟。</li><li>用高脚金属漏斗过滤，弃滤渣。</li><li>请将魅惑晶核置于诱导员呼吸道内，观察魅惑反应；用解魅剂进行治疗，观察治疗效果。</li><li>若任意步骤失败，请求助课程教师。</li></ol><h2 id="实验结果" tabindex="-1"><a class="header-anchor" href="#实验结果" aria-hidden="true">#</a> 实验结果</h2><ol><li>以特波同学为诱导，魅魔雾气具人化为类SKY老师形态，着蓝色夹克衫与黑色西装裤，尾端未露出，其他魅魔特征均未显露。</li><li>在SKY老师的帮助下，魅魔雾气具人化为类特波形态，尾巴发育良好，桃心明显。</li><li>特波形态魅魔自动流出大量唾液，质地清澈。SKY老师协助收集。</li><li>分离凝华后，所提取的魅惑晶核色泽通透，为海洋蓝色。</li><li>诱导员被置入魅惑晶核后，面色坨红，持续微喘，反应剧烈且对解魅剂无反应。</li></ol><h2 id="讨论" tabindex="-1"><a class="header-anchor" href="#讨论" aria-hidden="true">#</a> 讨论</h2><ol><li>魅魔具人化过程中会贴近具人化对象形象，若对象正气过于充足，会导致魅魔特质丢失。</li><li>由于后续实验诱导员魅惑反应过于严重，由SKY老师接管治疗，故没有进一步的记录。</li></ol>',14),d=[h];function t(n,o){return l(),a("div",null,d)}const _=i(r,[["render",t],["__file","魔法师和我.html.vue"]]);export{_ as default};
